import{_ as t,c as a,o as r,a1 as o}from"./chunks/framework.DILC4Csi.js";const p=JSON.parse('{"title":"Прерывание потоковой передачи: устранение 0 токенов | Antigravity-Manager","description":"Научитесь пути устранения неполадок прерывания потоковой передачи, 0 Token и недействительной подписи в Antigravity Tools. Подтвердите /v1/messages или вызов потоковой передачи Gemini, прочитайте peek предчтение и отступление повторной попытки, в сочетании с Proxy Monitor и логами быстро определите причину и решите, нужно ли ротировать аккаунты.","frontmatter":{"title":"Прерывание потоковой передачи: устранение 0 токенов | Antigravity-Manager","sidebarTitle":"Самовосстановление или ручное вмешательство","subtitle":"Прерывание потоковой передачи/0 Token/недействительная подпись: механизм самовосстановления и путь устранения","description":"Научитесь пути устранения неполадок прерывания потоковой передачи, 0 Token и недействительной подписи в Antigravity Tools. Подтвердите /v1/messages или вызов потоковой передачи Gemini, прочитайте peek предчтение и отступление повторной попытки, в сочетании с Proxy Monitor и логами быстро определите причину и решите, нужно ли ротировать аккаунты.","tags":["faq","streaming","troubleshooting","retry"],"prerequisite":["start-getting-started","start-first-run-data","advanced-monitoring","advanced-scheduling"],"order":5},"headers":[],"relativePath":"ru/lbjlaq/Antigravity-Manager/faq/streaming-0token/index.md","filePath":"ru/lbjlaq/Antigravity-Manager/faq/streaming-0token/index.md"}'),i={name:"ru/lbjlaq/Antigravity-Manager/faq/streaming-0token/index.md"};function s(d,e,l,n,c,h){return r(),a("div",null,[...e[0]||(e[0]=[o('<h1 id="прерывание-потоковои-передачи-0-token-недеиствительная-подпись-механизм-самовосстановления-и-путь-устранения" tabindex="-1">Прерывание потоковой передачи/0 Token/недействительная подпись: механизм самовосстановления и путь устранения <a class="header-anchor" href="#прерывание-потоковои-передачи-0-token-недеиствительная-подпись-механизм-самовосстановления-и-путь-устранения" aria-label="Permalink to &quot;Прерывание потоковой передачи/0 Token/недействительная подпись: механизм самовосстановления и путь устранения&quot;">​</a></h1><p>В Antigravity Tools при вызове <code>/v1/messages</code> (совместимость с Anthropic) или нативных интерфейсов потоковой передачи Gemini, если вы сталкиваетесь с проблемами типа &quot;прерывание потокового вывода&quot;, &quot;200 OK но 0 Token&quot;, &quot;Invalid `signature`&quot;, этот урок дает вам путь устранения от UI до логов.</p><h2 id="чему-вы-научитесь" tabindex="-1">Чему вы научитесь <a class="header-anchor" href="#чему-вы-научитесь" aria-label="Permalink to &quot;Чему вы научитесь&quot;">​</a></h2><ul><li>Знать, что проблемы 0 Token/прерывания в прокси обычно сначала перехватываются &quot;peek предчтением&quot;</li><li>Можете из Proxy Monitor подтвердить аккаунт и сопоставленную модель этого запроса (<code>X-Account-Email</code> / <code>X-Mapped-Model</code>)</li><li>Можете через логи определить, это &quot;раннее завершение потока апстрима&quot;, &quot;отступление повторной попытки&quot;, &quot;ротация аккаунтов&quot; или &quot;повторная попытка исправления подписи&quot;</li><li>Знать, какие ситуации нужно ждать самовосстановления прокси, какие нужно вмешиваться вручную</li></ul><h2 id="ваша-текущая-проблема" tabindex="-1">Ваша текущая проблема <a class="header-anchor" href="#ваша-текущая-проблема" aria-label="Permalink to &quot;Ваша текущая проблема&quot;">​</a></h2><p>Вы можете видеть эти &quot;симптомы&quot;, но не знаете, с чего начать:</p><ul><li>Потоковый вывод прерывается на полпути, клиент &quot;застрял&quot; и не продолжается</li><li>200 OK, но <code>usage.output_tokens=0</code> или контент пуст</li><li>В ошибке 400 появляются <code>Invalid \\</code>signature`<code>, </code>Corrupted thought signature<code>, </code>must be `thinking`` и т.д.</li></ul><p>Эти проблемы в основном не &quot;вы неправильно написали запрос&quot;, а потоковая передача, ограничение скорости/колебания апстрима, или блоки подписей, переносимые историческими сообщениями, вызвали проверку апстрима. Antigravity Tools сделало несколько линий обороны на слое прокси, вам нужно только проверить, на каком шаге он застрял, по фиксированному пути.</p><h2 id="что-такое-0-token" tabindex="-1">Что такое 0 Token? <a class="header-anchor" href="#что-такое-0-token" aria-label="Permalink to &quot;Что такое 0 Token?&quot;">​</a></h2><p><strong>0 Token</strong> обычно относится к <code>output_tokens=0</code>, возвращаемому одним запросом, и выглядит &quot;не сгенерировал контент&quot;. В Antigravity Tools чаще причина в том, что &quot;потоковый ответ заканчивается/ошибается до реального вывода&quot;, а не модель реально сгенерировала 0 токенов. Прокси попытается перехватить этот пустой ответ с помощью peek предчтения и запустить повторную попытку.</p><h2 id="три-вещи-которые-делает-прокси-за-кулисами-сначала-создаите-ментальную-модель" tabindex="-1">Три вещи, которые делает прокси за кулисами (сначала создайте ментальную модель) <a class="header-anchor" href="#три-вещи-которые-делает-прокси-за-кулисами-сначала-создаите-ментальную-модель" aria-label="Permalink to &quot;Три вещи, которые делает прокси за кулисами (сначала создайте ментальную модель)&quot;">​</a></h2><h3 id="_1-непотоковые-запросы-могут-быть-автоматически-преобразованы-в-потоковые" tabindex="-1">1) Непотоковые запросы могут быть автоматически преобразованы в потоковые <a class="header-anchor" href="#_1-непотоковые-запросы-могут-быть-автоматически-преобразованы-в-потоковые" aria-label="Permalink to &quot;1) Непотоковые запросы могут быть автоматически преобразованы в потоковые&quot;">​</a></h3><p>В маршруте <code>/v1/messages</code>, прокси внутренне преобразует &quot;непотоковый запрос клиента&quot; в потоковый запрос для запроса апстрима, и после получения SSE собирает в JSON и возвращает (причина в логах написана как &quot;better quota&quot;).</p><p>Доказательство исходного кода: <code>src-tauri/src/proxy/handlers/claude.rs#L665-L913</code>.</p><h3 id="_2-peek-предчтение-сначала-дождитесь-первого-блока-деиствительных-данных-затем-передаите-поток-клиенту" tabindex="-1">2) Peek предчтение: сначала дождитесь &quot;первого блока действительных данных&quot;, затем передайте поток клиенту <a class="header-anchor" href="#_2-peek-предчтение-сначала-дождитесь-первого-блока-деиствительных-данных-затем-передаите-поток-клиенту" aria-label="Permalink to &quot;2) Peek предчтение: сначала дождитесь &quot;первого блока действительных данных&quot;, затем передайте поток клиенту&quot;">​</a></h3><p>Для вывода SSE <code>/v1/messages</code>, прокси сначала <code>timeout + next()</code> предчитает, пропускает строки heartbeat/комментарии (начинаются с <code>:</code>), пока не получит первый блок данных, который &quot;не пустой, не heartbeat&quot;, затем начинает реальную пересылку. Если на этапе peek ошибка/timeout/поток заканчивается, сразу перейдет к следующей попытке (следующий раунд обычно вызовет ротацию аккаунтов).</p><p>Доказательство исходного кода: <code>src-tauri/src/proxy/handlers/claude.rs#L812-L926</code>; у нативного потокового Gemini также есть похожий peek: <code>src-tauri/src/proxy/handlers/gemini.rs#L117-L149</code>.</p><h3 id="_3-единое-отступление-повторнои-попытки-решение-ротировать-ли-аккаунты-по-коду-состояния" tabindex="-1">3) Единое отступление повторной попытки + решение &quot;ротировать ли аккаунты&quot; по коду состояния <a class="header-anchor" href="#_3-единое-отступление-повторнои-попытки-решение-ротировать-ли-аккаунты-по-коду-состояния" aria-label="Permalink to &quot;3) Единое отступление повторной попытки + решение &quot;ротировать ли аккаунты&quot; по коду состояния&quot;">​</a></h3><p>Прокси сделал четкую стратегию отступления для распространенных кодов состояния, и определил, какие коды состояния вызовут ротацию аккаунтов.</p><p>Доказательство исходного кода: <code>src-tauri/src/proxy/handlers/claude.rs#L117-L236</code>.</p><h2 id="🎒-подготовка-перед-началом" tabindex="-1">🎒 Подготовка перед началом <a class="header-anchor" href="#🎒-подготовка-перед-началом" aria-label="Permalink to &quot;🎒 Подготовка перед началом&quot;">​</a></h2><ul><li>Вы можете открыть Proxy Monitor (см. <a href="/docs/opencodedocs/ru/lbjlaq/Antigravity-Manager/advanced/monitoring/">Proxy Monitor: логи запросов, фильтрация, восстановление деталей и экспорт</a>)</li><li>Вы знаете, что логи находятся в каталоге <code>logs/</code> каталога данных (см. <a href="/docs/opencodedocs/ru/lbjlaq/Antigravity-Manager/start/first-run-data/">Первый запуск обязательно: каталог данных, логи, системный трей и автозапуск</a>)</li></ul><h2 id="делаите-вместе-со-мнои" tabindex="-1">Делайте вместе со мной <a class="header-anchor" href="#делаите-вместе-со-мнои" aria-label="Permalink to &quot;Делайте вместе со мной&quot;">​</a></h2><h3 id="шаг-1-подтвердите-какои-маршрут-интерфеиса-вы-вызываете" tabindex="-1">Шаг 1: Подтвердите, какой маршрут интерфейса вы вызываете <a class="header-anchor" href="#шаг-1-подтвердите-какои-маршрут-интерфеиса-вы-вызываете" aria-label="Permalink to &quot;Шаг 1: Подтвердите, какой маршрут интерфейса вы вызываете&quot;">​</a></h3><p><strong>Зачем</strong> Детали самовосстановления <code>/v1/messages</code> (claude handler) и нативного Gemini (gemini handler) различны, сначала подтвердите маршрут, чтобы не тратить время впустую на неправильные ключевые слова логов.</p><p>Откройте Proxy Monitor, найдите тот неудачный запрос, сначала запишите Path:</p><ul><li><code>/v1/messages</code>: смотрите логику <code>src-tauri/src/proxy/handlers/claude.rs</code></li><li><code>/v1beta/models/...:streamGenerateContent</code>: смотрите логику <code>src-tauri/src/proxy/handlers/gemini.rs</code></li></ul><p><strong>Вы должны увидеть</strong>: В записи запроса вы можете увидеть URL/метод/код состояния (а также время выполнения запроса).</p><h3 id="шаг-2-из-заголовков-ответа-захватите-аккаунт-сопоставленная-модель" tabindex="-1">Шаг 2: Из заголовков ответа захватите &quot;аккаунт + сопоставленная модель&quot; <a class="header-anchor" href="#шаг-2-из-заголовков-ответа-захватите-аккаунт-сопоставленная-модель" aria-label="Permalink to &quot;Шаг 2: Из заголовков ответа захватите &quot;аккаунт + сопоставленная модель&quot;&quot;">​</a></h3><p><strong>Зачем</strong> Неудача/успех одного и того же запроса, во многом зависит от &quot;какой аккаунт выбран&quot;, &quot;на какую модель апстрима маршрутизирован&quot;. Прокси напишет эти две информации в заголовки ответа, сначала запишите, позже в логах можно сопоставить.</p><p>В неудачном запросе найдите эти заголовки ответа:</p><ul><li><code>X-Account-Email</code></li><li><code>X-Mapped-Model</code></li></ul><p>Эти два элемента устанавливаются в обоих handler <code>/v1/messages</code> и Gemini handler (например, в ответе SSE <code>/v1/messages</code>: <code>src-tauri/src/proxy/handlers/claude.rs#L887-L896</code>; SSE Gemini: <code>src-tauri/src/proxy/handlers/gemini.rs#L235-L245</code>).</p><p><strong>Вы должны увидеть</strong>: <code>X-Account-Email</code> - это почта, <code>X-Mapped-Model</code> - это имя фактически запрошенной модели.</p><h3 id="шаг-3-в-app-log-определите-не-не-удалось-ли-на-этапе-peek" tabindex="-1">Шаг 3: В app.log определите, не &quot;не удалось ли на этапе peek&quot; <a class="header-anchor" href="#шаг-3-в-app-log-определите-не-не-удалось-ли-на-этапе-peek" aria-label="Permalink to &quot;Шаг 3: В app.log определите, не &quot;не удалось ли на этапе peek&quot;&quot;">​</a></h3><p><strong>Зачем</strong> Неудача peek обычно означает &quot;апстрим вообще не начал выводить действительные данные&quot;. Для этого типа проблем чаще всего способ обработки - повторная попытка/ротация аккаунтов, вам нужно подтвердить, запустил ли прокси.</p><p>Сначала найдите файл логов (каталог логов из каталога данных <code>logs/</code>, и записывается по дням в <code>app.log*</code>).</p><div class="vp-code-group vp-adaptive-theme"><div class="tabs"><input type="radio" name="group-NmbPT" id="tab-3I-Kupl" checked><label data-title="macOS/Linux" for="tab-3I-Kupl">macOS/Linux</label><input type="radio" name="group-NmbPT" id="tab-almCTFx"><label data-title="Windows" for="tab-almCTFx">Windows</label></div><div class="blocks"><div class="language-bash vp-adaptive-theme active"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ls</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -lt</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$HOME</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/.antigravity_tools/logs&quot;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> head</span></span></code></pre></div><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">Get-ChildItem</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> -</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Force (</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">Join-Path</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> $HOME</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;.antigravity_tools\\logs&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">) </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">|</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> Sort-Object</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> LastWriteTime </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Descending </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">|</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> Select-Object</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> -</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">First </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">5</span></span></code></pre></div></div></div><p>Затем в последнем <code>app.log*</code> найдите эти ключевые слова:</p><ul><li><code>/v1/messages</code> (claude handler): <code>Stream error during peek</code> / <code>Stream ended during peek</code> / <code>Timeout waiting for first data</code> (<code>src-tauri/src/proxy/handlers/claude.rs#L828-L864</code>)</li><li>Нативный потоковый Gemini: <code>[Gemini] Empty first chunk received, retrying...</code> / <code>Stream error during peek</code> / <code>Stream ended immediately</code> (<code>src-tauri/src/proxy/handlers/gemini.rs#L117-L144</code>)</li></ul><p><strong>Вы должны увидеть</strong>: Если запущена повторная попытка peek, в логах появится похожее предупреждение &quot;retrying...&quot;, и随后 перейдет к следующему attempt (обычно приведет к ротации аккаунтов).</p><h3 id="шаг-4-если-400-invalid-signature-подтвердите-сделал-ли-прокси-повторную-попытку-исправления-подписи" tabindex="-1">Шаг 4: Если 400/Invalid <code>signature</code>, подтвердите, сделал ли прокси &quot;повторную попытку исправления подписи&quot; <a class="header-anchor" href="#шаг-4-если-400-invalid-signature-подтвердите-сделал-ли-прокси-повторную-попытку-исправления-подписи" aria-label="Permalink to &quot;Шаг 4: Если 400/Invalid `signature`, подтвердите, сделал ли прокси &quot;повторную попытку исправления подписи&quot;&quot;">​</a></h3><p><strong>Зачем</strong> Ошибки подписи часто приходят от блоков Thinking/блоков подписей в исторических сообщениях, которые не соответствуют требованиям апстрима. Antigravity Tools попытается &quot;понижение исторических блоков thinking + введение исправленного промпта&quot; затем повторить попытку, вы должны сначала позволить ему пройти самовосстановление.</p><p>Вы можете использовать 2 сигнала, чтобы определить, вошел ли он в логику исправления:</p><ol><li>В логах появляется <code>Unexpected thinking signature error ... Retrying with all thinking blocks removed.</code> (<code>src-tauri/src/proxy/handlers/claude.rs#L999-L1025</code>)</li><li>Затем исторические блоки <code>Thinking</code> будут преобразованы в <code>Text</code>, и в последнем сообщении user будет добавлен исправленный промпт (<code>src-tauri/src/proxy/handlers/claude.rs#L1027-L1102</code>; gemini handler также добавит тот же исправленный промпт к <code>contents[].parts</code>: <code>src-tauri/src/proxy/handlers/gemini.rs#L300-L325</code>)</li></ol><p><strong>Вы должны увидеть</strong>: Прокси автоматически повторит попытку после короткой задержки (<code>FixedDelay</code>), и может войти в следующую попытку.</p><h2 id="контрольная-точка-✅" tabindex="-1">Контрольная точка ✅ <a class="header-anchor" href="#контрольная-точка-✅" aria-label="Permalink to &quot;Контрольная точка ✅&quot;">​</a></h2><ul><li>[ ] Вы можете подтвердить маршрут запроса в Proxy Monitor (<code>/v1/messages</code> или нативный Gemini)</li><li>[ ] Вы можете получить <code>X-Account-Email</code> и <code>X-Mapped-Model</code> этого запроса</li><li>[ ] Вы можете найти ключевые слова peek/повторная попытка в <code>logs/app.log*</code></li><li>[ ] При ошибке 400 подписи вы можете подтвердить, вошел ли прокси в логику повторной попытки &quot;исправленный промпт + очистка блоков thinking&quot;</li></ul><h2 id="предупреждения-о-типичных-ошибках" tabindex="-1">Предупреждения о типичных ошибках <a class="header-anchor" href="#предупреждения-о-типичных-ошибках" aria-label="Permalink to &quot;Предупреждения о типичных ошибках&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Сценарий</th><th>Что вы можете сделать (❌)</th><th>Рекомендуемый способ (✓)</th></tr></thead><tbody><tr><td>При виде 0 Token сразу много раз вручную повторять</td><td>Постоянно нажимать кнопку повтора клиента, совсем не смотреть логи</td><td>Сначала посмотрите Proxy Monitor + app.log один раз, подтвердите, это ли ранняя неудача на этапе peek (автоматически повторит/ротирует)</td></tr><tr><td>При <code>Invalid \\</code>signature`` сразу очистить каталог данных</td><td>Удалить весь <code>.antigravity_tools</code>, аккаунты/статистика все пропали</td><td>Сначала позвольте прокси выполнить один раз &quot;повторную попытку исправления подписи&quot;; только когда лог явно показывает, что восстановление невозможно, рассмотрите ручное вмешательство</td></tr><tr><td>Считать &quot;колебание сервера&quot; как &quot;аккаунт сломан&quot;</td><td>400/503/529一律 ротировать аккаунты</td><td>Действенность ротации зависит от кода состояния; у прокси сами есть правила <code>should_rotate_account(...)</code> (<code>src-tauri/src/proxy/handlers/claude.rs#L226-L236</code>)</td></tr></tbody></table><h2 id="краткии-итог-урока" tabindex="-1">Краткий итог урока <a class="header-anchor" href="#краткии-итог-урока" aria-label="Permalink to &quot;Краткий итог урока&quot;">​</a></h2><ul><li>0 Token/прерывание потоковой передачи в прокси обычно сначала проходит через peek предчтение; неудача на этапе peek вызовет повторную попытку и перейдет к следующему attempt</li><li><code>/v1/messages</code> может внутренне преобразовать непотоковый запрос в потоковый затем собрать обратно в JSON, это повлияет на ваше понимание &quot;почему похоже на проблему потоковой передачи&quot;</li><li>Ошибки недействительности подписи 400, прокси попытается &quot;исправленный промпт + очистка блоков thinking&quot; затем повторить попытку, вы сначала подтвердите, прошел ли этот путь самовосстановления</li></ul><h2 id="следующии-урок预告" tabindex="-1">Следующий урок预告 <a class="header-anchor" href="#следующии-урок预告" aria-label="Permalink to &quot;Следующий урок预告&quot;">​</a></h2><blockquote><p>Следующий урок мы изучим <strong><a href="/docs/opencodedocs/ru/lbjlaq/Antigravity-Manager/appendix/endpoints/">Справочник по точкам доступа</a></strong>.</p></blockquote><hr><h2 id="приложение-справка-по-исходному-коду" tabindex="-1">Приложение: Справка по исходному коду <a class="header-anchor" href="#приложение-справка-по-исходному-коду" aria-label="Permalink to &quot;Приложение: Справка по исходному коду&quot;">​</a></h2><details><summary><strong>Нажмите, чтобы увидеть местоположение исходного кода</strong></summary><blockquote><p>Обновлено: 2026-01-23</p></blockquote><table tabindex="0"><thead><tr><th>Функция</th><th>Путь к файлу</th><th>Строки</th></tr></thead><tbody><tr><td>Claude handler: стратегия отступления повторной попытки + правила ротации</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/handlers/claude.rs#L117-L236" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/handlers/claude.rs</code></a></td><td>117-236</td></tr><tr><td>Claude handler: внутренне преобразует непотоковый в потоковый (better quota)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/handlers/claude.rs#L665-L776" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/handlers/claude.rs</code></a></td><td>665-776</td></tr><tr><td>Claude handler: peek предчтение (пропуск heartbeat/комментариев, избегая пустой поток)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/handlers/claude.rs#L812-L926" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/handlers/claude.rs</code></a></td><td>812-926</td></tr><tr><td>Claude handler: повторная попытка исправления ошибки 400 подписи/неправильного порядка блоков</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/handlers/claude.rs#L999-L1102" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/handlers/claude.rs</code></a></td><td>999-1102</td></tr><tr><td>Gemini handler: peek предчтение (предотвратить пустой поток 200 OK)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/handlers/gemini.rs#L117-L149" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/handlers/gemini.rs</code></a></td><td>117-149</td></tr><tr><td>Gemini handler: введение исправленного промпта при ошибке 400 подписи</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/handlers/gemini.rs#L300-L325" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/handlers/gemini.rs</code></a></td><td>300-325</td></tr><tr><td>Кеш подписей (три слоя: tool/family/session, с TTL/минимальная длина)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/signature_cache.rs#L5-L207" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/signature_cache.rs</code></a></td><td>5-207</td></tr><tr><td>Преобразование Claude SSE: захват подписи и запись в кеш подписей</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/mappers/claude/streaming.rs#L639-L787" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/mappers/claude/streaming.rs</code></a></td><td>639-787</td></tr></tbody></table><p><strong>Ключевые константы</strong>:</p><ul><li><code>MAX_RETRY_ATTEMPTS = 3</code>: максимальное количество повторных попыток (<code>src-tauri/src/proxy/handlers/claude.rs#L27</code>)</li><li><code>SIGNATURE_TTL = 2 * 60 * 60</code> секунд: TTL кеша подписей (<code>src-tauri/src/proxy/signature_cache.rs#L6</code>)</li><li><code>MIN_SIGNATURE_LENGTH = 50</code>: минимальная длина подписи (<code>src-tauri/src/proxy/signature_cache.rs#L7</code>)</li></ul><p><strong>Ключевые функции</strong>:</p><ul><li><code>determine_retry_strategy(...)</code>: выбрать стратегию отступления по коду состояния (<code>src-tauri/src/proxy/handlers/claude.rs#L117-L167</code>)</li><li><code>should_rotate_account(...)</code>: решить, ротировать ли аккаунты по коду состояния (<code>src-tauri/src/proxy/handlers/claude.rs#L226-L236</code>)</li><li><code>SignatureCache::cache_session_signature(...)</code>: кешировать подпись сессии (<code>src-tauri/src/proxy/signature_cache.rs#L149-L188</code>)</li></ul></details>',57)])])}const g=t(i,[["render",s]]);export{p as __pageData,g as default};
